                      <CurrencyTextField
                        label="Amount"
                        variant="standard"
                        value={formdata.amount}
                        currencySymbol="$"
                        outputFormat="string"
                        decimalCharacter="."
                        digitGroupSeparator=","
                        decimalPlaces="2"
                        className={classes.textField}
                        id="standard-amount"
                        name="amount"
                        style={{ width: 100 }}
                        //onChange={onChange}
                        onChange={(e) => {
                          onChange(parseFloat(currency(e.target.value), 10));
                        }}
                        error={!!error}
                        helperText={error ? error.message : null}
                      />
                    );
                  }}
                  //rules={{ required: "IC No required" }}
                />
              </div>
              <div>
                <Controller
                  name="remark"
                  control={control}
                  defaultValue={formdata.remark}
