                    fieldState: { error },
                  }) => {
                    return (
                      <TextField
                        label="Attachment #2"
                        id="margin-normal6"
                        name="attachment2_name"
                        defaultValue={formdata.attachment2_name}
                        className={classes.textField}
                        onChange={onChange}
                        error={!!error}
                        helperText={error ? error.message : null}
                        InputProps={{
                          readOnly: true,
                        }}
                      ></TextField>
                    );
                  }}
                />
              </div> */}
              {/* <div>
                <Controller
                  name="attachment3_name"
                  control={control}
                  defaultValue={formdata.attachment3_name}
                  render={({
                    field: { onChange, value },
                    fieldState: { error },
                  }) => {
                    return (
                      <TextField
                        label="Attachment #3"
                        id="margin-normal6"
                        name="attachment3_name"
                        defaultValue={formdata.attachment3_name}
                        className={classes.textField}
                        onChange={onChange}
                        error={!!error}
                        helperText={error ? error.message : null}
                        InputProps={{
                          readOnly: true,
                        }}
                      ></TextField>
                    );
                  }}
                />
              </div> */}

              {formdata.status === "Pending" && (
                <div>
                  <Button
                    type="submit"
                    variant="contained"
                    color="primary"
                    className={classes.button}
                    //onClick={() => handleSubmit(onSubmit)()}
                  >
                    Save <Icon className={classes.rightIcon}>send</Icon>
                  </Button>
                </div>
              )}
            </GridItem>
            <GridItem colSpan={2}>
              <ImageUpload files={files} setFiles={setFiles} onDrop={onDrop} />
            </GridItem>
          </Grid>
        </form>
      </Box>
    </div>
  );
};

